import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as s}from"./app-ef36cc2e.js";const i={},t=s('<h1 id="面试-spring" tabindex="-1"><a class="header-anchor" href="#面试-spring" aria-hidden="true">#</a> 面试-Spring</h1><h3 id="对spring的理解" tabindex="-1"><a class="header-anchor" href="#对spring的理解" aria-hidden="true">#</a> 对Spring的理解</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：对Spring的理解</b></summary><p><b style="color:#f19977;">答：Spring核心思想为IOC、DI、AOP。Spring框架使用了Java里面的反射机制。IOC就是把对象的创建控制权转移到IOC容器并且负责对象的创建、初始化等一系列工作。被创建的对象在IOC容器中称为Bean。在容器中建立Bean与Bean之间的关系就称为依赖注入。AOP底层是代理模式，可以在不改变原有代码结构的情况下增强功能。</b></p></details><h3 id="spring的二种注入方式" tabindex="-1"><a class="header-anchor" href="#spring的二种注入方式" aria-hidden="true">#</a> Spring的二种注入方式</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Spring的二种注入方式</b></summary><p><b style="color:#f19977;">答：setter方式和构造方法的方式</b></p></details><h3 id="aop有哪些应用场景" tabindex="-1"><a class="header-anchor" href="#aop有哪些应用场景" aria-hidden="true">#</a> AOP有哪些应用场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：AOP有哪些应用场景</b></summary><p><b style="color:#f19977;">答：事务管理、日志打印。</b></p></details><h3 id="autowired-和-resource的区别" tabindex="-1"><a class="header-anchor" href="#autowired-和-resource的区别" aria-hidden="true">#</a> @Autowired 和@Resource的区别?</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：@Autowired 和@Resource 的区别?</b></summary><p><b style="color:#f19977;">答：@Autowired是按照类型进行注入，没有类型会按照名称进行注入。@Resource会按照名称注入，名称找不着会按照类型来找。</b></p></details><h3 id="为什么bean要设计成单例" tabindex="-1"><a class="header-anchor" href="#为什么bean要设计成单例" aria-hidden="true">#</a> 为什么Bean要设计成单例</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：为什么Bean要设计成单例</b></summary><p><b style="color:#f19977;">答：资源利用效率：单例模式可以节省系统资源，避免重复创建和销毁对象。当一个对象被多次请求时，只需要创建一次实例并重复使用，提高了系统的资源利用效率。对象一致性：对于某些需要保持一致状态或共享数据的对象，使用单例模式可以确保全局只有一个实例。这样可以避免多个实例之间的数据不一致性问题，简化了数据管理和同步的复杂性。全局访问性：单例模式使得对象在整个应用程序的上下文中可被访问。这对于需要在不同的组件或模块中共享数据或提供共享服务的对象非常有用。配置和管理简便性：在Spring框架中，Bean的单例模式使得对象的创建、依赖注入和生命周期管理更加简便。通过Spring容器的管理，可以统一配置和管理Bean的创建和销毁过程。</b></p></details>',11),n=[t];function o(d,l){return a(),r("div",null,n)}const p=e(i,[["render",o],["__file","面试-Spring.html.vue"]]);export{p as default};
